# recurrence_detector.py - identify recurring incident patterns across postmortems
from dataclasses import dataclass, field
from collections import Counter, defaultdict
from typing import List, Dict, Tuple
from datetime import date


@dataclass
class IncidentRecord:
    incident_id: str
    date: date
    severity: str
    incident_type: str       # prompt-regression | tool-budget | eval-drift | infra | safety
    root_cause_category: str # process | model | tooling | people | data | environment
    affected_service: str
    duration_minutes: int
    postmortem_action_items: int


@dataclass
class RecurrenceCluster:
    cluster_key: str           # e.g. 'prompt-regression:process'
    incident_type: str
    root_cause_category: str
    incidents: List[IncidentRecord] = field(default_factory=list)

    @property
    def count(self) -> int:
        return len(self.incidents)

    @property
    def is_systemic(self) -> bool:
        # Three or more incidents of same type+root_cause = systemic
        return self.count >= 3

    @property
    def total_minutes_lost(self) -> int:
        return sum(i.duration_minutes for i in self.incidents)


def find_recurrence_clusters(
    incidents: List[IncidentRecord],
    lookback_days: int = 180,
) -> List[RecurrenceCluster]:
    cutoff = date.today()
    # In production, filter by date.today() - timedelta(days=lookback_days)

    clusters: Dict[str, RecurrenceCluster] = {}
    for inc in incidents:
        key = f'{inc.incident_type}:{inc.root_cause_category}'
        if key not in clusters:
            clusters[key] = RecurrenceCluster(
                cluster_key=key,
                incident_type=inc.incident_type,
                root_cause_category=inc.root_cause_category,
            )
        clusters[key].incidents.append(inc)

    return sorted(clusters.values(), key=lambda c: c.count, reverse=True)


def systemic_risk_report(incidents: List[IncidentRecord]) -> dict:
    clusters = find_recurrence_clusters(incidents)
    systemic = [c for c in clusters if c.is_systemic]
    return {
        'total_incidents': len(incidents),
        'total_clusters': len(clusters),
        'systemic_clusters': len(systemic),
        'systemic_details': [
            {
                'cluster': c.cluster_key,
                'count': c.count,
                'total_minutes_lost': c.total_minutes_lost,
                'recommendation': (
                    'Strategic investment required — tactical patches are not working'
                    if c.count >= 5 else
                    'Systemic gap — allocate sprint capacity for root fix'
                ),
            }
            for c in systemic
        ],
    }


if __name__ == '__main__':
    import json
    from datetime import date
    incidents = [
        IncidentRecord('INC-30', date(2026, 1, 10), 'SEV-2', 'prompt-regression', 'process', 'agent-cs', 45, 3),
        IncidentRecord('INC-35', date(2026, 2, 5), 'SEV-2', 'prompt-regression', 'process', 'agent-cs', 60, 4),
        IncidentRecord('INC-38', date(2026, 3, 12), 'SEV-3', 'prompt-regression', 'process', 'agent-code', 30, 2),
        IncidentRecord('INC-40', date(2026, 4, 1), 'SEV-2', 'prompt-regression', 'process', 'agent-cs', 90, 5),
        IncidentRecord('INC-42', date(2026, 5, 14), 'SEV-2', 'tool-budget', 'tooling', 'agent-cs', 58, 4),
        IncidentRecord('INC-44', date(2026, 6, 20), 'SEV-1', 'tool-budget', 'tooling', 'agent-data', 120, 6),
        IncidentRecord('INC-46', date(2026, 7, 8), 'SEV-2', 'tool-budget', 'tooling', 'agent-cs', 45, 3),
    ]
    report = systemic_risk_report(incidents)
    print(json.dumps(report, indent=2))

# prevention_guard.py - enforce prevention controls at deploy time
# Integrates with CI/CD to block deployments that match known recurrence patterns
import json
import sys
from dataclasses import dataclass
from typing import List, Optional


@dataclass
class PreventionControl:
    id: str
    cluster_key: str         # e.g. 'prompt-regression:process'
    description: str
    check_fn_name: str       # function to call to verify control is in place
    severity: str            # 'block' (fails CI) or 'warn' (advisory)


REGISTERED_CONTROLS: List[PreventionControl] = [
    PreventionControl(
        id='PC-01',
        cluster_key='prompt-regression:process',
        description='Prompt changes must have eval CI pass before merge',
        check_fn_name='check_eval_ci_gate',
        severity='block',
    ),
    PreventionControl(
        id='PC-02',
        cluster_key='tool-budget-breach:tooling',
        description='All new tools must declare max_calls_per_session',
        check_fn_name='check_tool_budget_declared',
        severity='block',
    ),
    PreventionControl(
        id='PC-03',
        cluster_key='third-party-degradation:environment',
        description='LLM provider calls must have circuit breaker configured',
        check_fn_name='check_circuit_breaker_configured',
        severity='warn',
    ),
]


def check_eval_ci_gate(context: dict) -> bool:
    # Returns True if eval CI passed on this PR
    return context.get('eval_ci_status') == 'passed'


def check_tool_budget_declared(context: dict) -> bool:
    # Returns True if new tools in this diff declare budget constraints
    new_tools = context.get('new_tools_added', [])
    for tool in new_tools:
        if 'max_calls_per_session' not in tool:
            return False
    return True


def check_circuit_breaker_configured(context: dict) -> bool:
    return context.get('circuit_breaker_enabled', False)


CHECK_FUNCTIONS = {
    'check_eval_ci_gate': check_eval_ci_gate,
    'check_tool_budget_declared': check_tool_budget_declared,
    'check_circuit_breaker_configured': check_circuit_breaker_configured,
}


def run_prevention_checks(context: dict) -> dict:
    results = []
    blocked = False
    for control in REGISTERED_CONTROLS:
        fn = CHECK_FUNCTIONS.get(control.check_fn_name)
        passed = fn(context) if fn else False
        results.append({
            'control_id': control.id,
            'description': control.description,
            'passed': passed,
            'severity': control.severity,
        })
        if not passed and control.severity == 'block':
            blocked = True

    return {'blocked': blocked, 'results': results}


if __name__ == '__main__':
    context = {
        'eval_ci_status': 'passed',
        'new_tools_added': [{'name': 'delete_file', 'max_calls_per_session': 10}],
        'circuit_breaker_enabled': False,
    }
    result = run_prevention_checks(context)
    print(json.dumps(result, indent=2))
    sys.exit(1 if result['blocked'] else 0)
